  ('dietitian-moex-10827', 'dietitian', 'dietitian-moex-094-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '“statin”類藥物降血膽固醇之作用為： 促進lipoprotein lipase之活性  抑制膽酸之再吸收 抑制HMG CoA reductase之活性  促進LDL receptor之活性', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "8fcc596fc6ec", "answer_pdf_sha1": "c6d0f373e8c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
